p.m:
\displaystyle{\begin{aligned}
  \frac{{\frac{1}{b-1}-2}}{{\frac{1}{b-1}+\frac{1}{b-3}}} \amp = \frac{({\frac{1}{b-1}-2})\cdot{\left(b-1\right)\mathopen{}\left(b-3\right)}}{({\frac{1}{b-1}+\frac{1}{b-3}})\cdot{\left(b-1\right)\mathopen{}\left(b-3\right)}} \\
    \amp = \frac{{\frac{1}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-3\right)-2\mathopen{}\left(b-1\right)\mathopen{}\left(b-3\right)}}{{\frac{1}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-3\right)+\frac{1}{b-3}\mathopen{}\left(b-1\right)\mathopen{}\left(b-3\right)}} \\
    \amp = \frac{{b-3-2\mathopen{}\left(b^{2}-4b+3\right)}}{{b-3+b-1}}, b \ne 1 \text{ and } b \ne 3 \\
    \amp = \frac{{b-3-2b^{2}+8b-6}}{{2b-4}}, b \ne 1 \text{ and }  b \ne 3 \\
    \amp = \frac{{-2b^{2}+9b-6}}{{2b-4}}, b \ne 1 \text{ and }  b \ne 3 \\
    \amp = {-\frac{\left(2b-3\right)\mathopen{}\left(b-3\right)}{2\mathopen{}\left(b-2\right)}, b\ne 1\hbox{ and }b\ne 3}
\end{aligned}
    }
